mapper.select:
SELECT window_key, window_date, running, success, inserted_at, updated_at
FROM import_execution_state
WHERE window_key = #{windowKey}
  AND window_date = #{windowDate}

mapper.update:
UPDATE import_execution_state
SET running    = #{running},
    success    = #{success},
    updated_at = #{updatedAt}
WHERE window_key = #{windowKey}
  AND window_date = #{windowDate}
